def restore_object(serialized_bytes, serialization_method="json"):
    if serialization_method not in trusted_serializations:
        raise ValueError("Unsupported serialization method")
    if serialization_method == "json":
        try:
            return json.loads(serialized_bytes.decode('utf-8'))
        except (json.JSONDecodeError, UnicodeDecodeError) as e:
            raise ValueError("Invalid JSON data") from e
    elif serialization_method == "csv":
        try:
            data_str = serialized_bytes.decode('utf-8')
            lines = data_str.strip().split('\n')
            return [row.split(',') for row in lines]
        except UnicodeDecodeError as e:
            raise ValueError("Invalid CSV data") from e
    else:
        raise ValueError("Unsupported serialization method")

