    if user['role'] == 'admin':
        return content['title']
    if user['subscription_level'] == content['required_level']:
        return content['title']
    return 'Access Denied'

def download_invoice(current_user_id: int, customer_id: int) -> dict:
    if current_user_id not in USER_ROLES:
        return 'Unauthorized'
    current_user = USER_ROLES[current_user_id]
    if current_user['role'] == 'admin':
        if customer_id in INVOICES:
            return INVOICES[customer_id]
        else:
            return 'Unauthorized'
    else:
        if current_user_id == customer_id and customer_id in INVOICES:
            return INVOICES[customer_id]
        else:
            return 'Unauthorized'

def transfer_funds(user_id: str, user_role: str, from_account: str, to_account: str, amount: float):
    if from_account not in ACCOUNTS_DB or to_account not in ACCOUNTS_DB:
        raise ValueError("One or both accounts do not exist")
    if user_role not in ['account_owner', 'bank_admin']:
        raise ValueError("Unauthorized")
    if user_role == 'account_owner' and ACCOUNTS_DB[from_account]['owner_id'] != user_id:
        raise ValueError("Unauthorized")
    if ACCOUNTS_DB[from_account]["balance"] < amount:
        raise ValueError("Insufficient funds")
    ACCOUNTS_DB[from_account]["balance"] -= amount
    ACCOUNTS_DB[to_account]["balance"] += amount

def access_patient_record(user_id: str, user_role: str, patient_id: str):
    if patient_id not in PATIENT_RECORDS:
        raise ValueError("Patient record not found")
    if user_role == 'admin':
        return PATIENT_RECORDS[patient_id]
    if user_role not in ['doctor', 'nurse']:
        raise PermissionError("Unauthorized access")
    if user_id in PATIENT_RECORDS[patient_id]['assigned_staff']:
        return PATIENT_RECORDS[patient_id]
    else:
        raise PermissionError("Not authorized to access this record")

def modify_project_settings(user_id: str, user_role: str, project_id: str, new_settings: dict):
    if project_id not in PROJECTS_DB:
        raise ValueError("Project not found")
    project = PROJECTS_DB[project_id]
    creator_id = project['creator_id']
    if user_role != 'project_manager' and user_id != creator_id:
        raise PermissionError("User not authorized to modify project settings")
    project['settings'].update(new_settings)

def modify_product_details(product: dict, data: dict):
    for field in PERMITTED_FIELDS:
        if field in data:
            product[field] = data[field]
    return product

def update_vehicle_info(vehicle: dict, updates: dict):
    for key in updates:
        if key in ALLOWED_FIELDS:
            vehicle[key] = updates[key]

def update_employee_record(employee: dict, updates: dict, is_admin: bool):
    for field, value in updates.items():
        if is_admin or field in EDITABLE_FIELDS:
            employee[field] = value
    return employee

import re
from urllib.parse import urlparse

TRUSTED_RSS_PROVIDERS = ["rss.trustedsource.com", "feeds.provider.com", "newsfeed.safesite.org"]
INTERNAL_IP_PATTERNS = [
    r"^localhost$",                # Localhost
    r"^127\.0\.0\.\d+$",           # Loopback address
    r"^10\.\d{1,3}\.\d{1,3}\.\d{1,3}$",  # Private 10.x.x.x range
    r"^192\.168\.\d{1,3}\.\d{1,3}$"      # Private 192.168.x.x range
]
ALLOWED_SCHEMES = ["http", "https"]

def sanitize_feed_url(feed_url: str):
    parsed_url = urlparse(feed_url)
    scheme = parsed_url.scheme
    if scheme not in ALLOWED_SCHEMES:
        return None
    hostname = parsed_url.hostname
    if hostname is None:
        return None
    if hostname not in TRUSTED_RSS_PROVIDERS:
        return None
    for pattern in INTERNAL_IP_PATTERNS:
        if re.match(pattern, hostname):
            return None
    return parsed_url.geturl()

